function hash(value:string){let result=2166136261;for(const char of value)result=Math.imul(result^char.charCodeAt(0),16777619)>>>0;return result;}
function uniqueNotes(key:string,name:string,id="catatan-khusus"){const first=hash(key)%variants.length;let second=Math.floor(hash(key)/variants.length)%variants.length;if(second===first)second=(second+3)%variants.length;return idText(id,`Catatan pengadaan khusus ${name}`,variants[first],variants[second]);}

