const sectionHeadings:Record<string,string>={produksi:"Rencana produksi khusus",qc:"Rencana QC khusus",kemasan:"Kemasan dan logistik khusus",oem:"Strategi OEM atau ODM",pembelian:"Keputusan buyer",pengalaman:"Data setelah pengiriman",penawaran:"Struktur permintaan penawaran"};
function distinctBlocks(key:string,subject:string,prefix="produk"){
  return Object.entries(sectionVariants).map(([section,choices],index)=>idText(`${prefix}-${section}`,sectionHeadings[section],`${subject}: ${choices[hash(`${key}-${section}-${index}`)%choices.length]}`,`Dalam keputusan ${subject.toLowerCase()}, buyer menghubungkan hasil ${sectionHeadings[section].toLowerCase()} khusus ${subject.toLowerCase()} dengan varian, penggunaan, risiko, dan rencana repeat order yang disetujui.`));
}
function extraDistinctBlocks(key:string,subject:string,prefix="tambahan",count=3){
  const topics=["pembelian","produksi","qc","kemasan","oem","pengalaman","penawaran"];
  return topics.slice(0,count).map((section,index)=>{
    const choices=sectionVariants[section];
    return idText(`${prefix}-${section}-${index+1}`,`${sectionHeadings[section]} — ${subject}`,choices[hash(`${[...key].reverse().join("")}-${section}-${index}-extra`)%choices.length],`Catatan ${sectionHeadings[section].toLowerCase()} untuk ${subject.toLowerCase()} diperiksa kembali terhadap SKU, target pelanggan, kondisi Indonesia, dan bukti yang tersedia sebelum keputusan dibuat.`);
  });
}

function sourceImages(entity:ContentEntity,slug:string):LocalizedImage[]{
  const existing=entity.versions.en?.images??[];
  const sources=[existing[0]?.src,"/assets/dumbbell-production.webp","/assets/factory-cases/packaging-area-pbf.webp"].filter((item):item is string=>Boolean(item));
  return sources.slice(0,3).map((src,index)=>({id:`gambar-${index+1}`,src:indonesianImagePath(src,slug,index),alt:index===0?`${productName(entity)} profesional untuk fasilitas gym`:index===1?`Proses produksi nyata yang berkaitan dengan ${productName(entity).toLowerCase()}`:`Pemeriksaan dan kemasan ekspor ${productName(entity).toLowerCase()}`,caption:index===0?"Foto produk nyata PowerBaseFit; konfigurasi akhir mengikuti penawaran dan sampel yang disetujui.":index===1?"Tahap produksi nyata harus dihubungkan dengan kode produk dan kriteria pemeriksaan.":"Kemasan, identifikasi karton, dan pallet diperiksa sebelum pengiriman."}));
}

function materialText(slug:string,name:string){
  if(/cpu/i.test(slug))return `Untuk ${name}, istilah CPU harus dijelaskan melalui formulasi bagian yang dilapisi, inti, metode pembentukan atau penuangan, ikatan, kekerasan bila relevan, warna, dan hasil sampel. Nama bahan tidak membuktikan konstruksi lengkap atau daya tahan.`;
  if(/tpu/i.test(slug))return `TPU pada ${name} perlu dinilai dari komposisi bagian, tekstur, garis sambungan, tepi, marking, kebersihan, dan kemampuan mengulang warna. Buyer sebaiknya membandingkan sampel setelah penanganan serta pembersihan yang realistis.`;
  if(/(?:^|-)pu(?:-|$)/i.test(slug))return `Pada ${name} berbahan PU, pisahkan bahan lapisan, inti, dan metode bonding. Warna, kilap, gelembung, sambungan, marking, serta perlindungan area grip perlu memiliki batas visual dan referensi fisik.`;
  if(/rubber/i.test(slug))return `Untuk ${name} berlapis karet, periksa campuran, bau, tekstur, ikatan pada inti, kontak dengan lantai atau rak, dan variasi permukaan. Evaluasi tidak cukup dilakukan segera setelah membuka sampel; lakukan juga pembersihan dan penyimpanan normal.`;
  if(/steel|sus304|aluminum/i.test(slug))return `Komponen logam pada ${name} memerlukan grade atau deklarasi bahan yang sesuai, proses machining, tepi, sambungan, finishing, dan perlindungan korosi. Ukuran fungsional diperiksa setelah finishing karena coating atau polishing dapat mengubah interface.`;
  if(/cast-iron/i.test(slug))return `Untuk konstruksi besi cor pada ${name}, buyer memeriksa hasil cor, porositas, geometri, machining lanjutan, massa, tepi, permukaan kontak, dan lapisan pelindung. Finishing yang rapi tidak mengimbangi lubang atau bidang tumpu di luar spesifikasi.`;
  return `Bahan ${name} harus didefinisikan untuk setiap komponen kritis dan dikaitkan dengan fungsi. Sampel menilai sentuhan, tampilan, interface, dan perakitan; inspeksi batch membuktikan bahwa hasil dapat diulang pada jumlah produksi.`;
}

function geometryText(slug:string,name:string){
  if(/adjustable|selectorized/i.test(slug))return `${name} memiliki mekanisme pengaturan yang perlu diuji pada seluruh posisi: pemilihan, penguncian, pelepasan, indikator, clearance, dan perilaku setelah siklus berulang. Unit dan dudukan atau bench terkait diuji bersama bila dijual sebagai sistem.`;
  if(/hexagonal|hex-dumbbell/i.test(slug))return `Bentuk hex pada ${name} mengurangi kecenderungan menggelinding, tetapi alignment, bidang tumpu, lebar kepala, stabilitas, dan kesesuaian rak harus diperiksa. Perbedaan geometri antarberat dapat memengaruhi kerapian set dan ruang ambil.`;
  if(/round/i.test(slug))return `Kepala bulat ${name} harus dinilai bersama rak yang digunakan. Diameter dan lebar berubah menurut berat, sehingga akses tangan, jarak antarproduk, keseimbangan, marking, dan risiko bergerak di lantai perlu disimulasikan.`;
  if(/bench/i.test(slug))return `${name} perlu diperiksa pada semua posisi yang ditawarkan: footprint, tinggi, sudut, mekanisme pin, stabilitas lateral, gap pad, roda, handle, upholstery, dan kesesuaian dengan rack. Sampel lengkap harus dirakit dan dioperasikan.`;
  if(/rack|smith|trainer|cable|machine|jungle|frame/i.test(slug))return `${name} memerlukan gambar ukuran, area operasi, rangka, joint, kabel, pulley, adjustment, guard, hardware, anchor bila ada, dan akses servis. Buyer lokal memverifikasi lantai serta pemasangan; supplier mengidentifikasi komponen dan spare part.`;
  if(/plate/i.test(slug))return `${name} dinilai melalui berat, diameter, ketebalan, lubang, insert, kerataan, grip bila ada, dan interface dengan bar. Jika penggunaan melibatkan benturan, metode uji harus menyebut permukaan, tinggi, siklus, dan kriteria setelah pengujian.`;
  if(/handle|attachment|bar|rope/i.test(slug))return `${name} harus cocok dengan titik sambung, ruang gerak, grip, rotasi, dan beban penggunaan yang dimaksud. Weld, joint, bearing, knurling, coating, atau terminal diperiksa sebelum dan setelah uji fungsi.`;
  if(/kettlebell/i.test(slug))return `${name} perlu diperiksa pada berat, keseimbangan, bentuk jendela handle, diameter grip, sambungan, bidang dasar, marking, dan finishing. Set lengkap harus konsisten saat berjajar serta mudah dibedakan antarberat.`;
  return `Geometri ${name} dikaitkan dengan penggunaan, penyimpanan, pembersihan, dan perawatan. Dimensi, titik kontak, interface, serta ruang pengguna diverifikasi pada sampel lengkap tanpa menyimpulkan kompatibilitas hanya dari nama produk.`;
}
function productSpecificAngle(slug:string,name:string){
  if(slug==="home-gym-functional-trainer")return [`${name} dirancang untuk proyek ruang latihan privat yang tetap menuntut spesifikasi profesional. Buyer memetakan lebar pintu, tinggi ruang, posisi listrik bila ada, kebisingan, pengguna, akses servis, dan kemampuan membawa modul sampai lokasi.`,"Jangan menganggap label home gym berarti ringan atau bebas pemasangan. Daftar modul, tumpukan beban, kabel, attachment, guard, hardware, area latihan, urutan perakitan, dan perlindungan lantai perlu disepakati untuk rumah premium, apartemen, atau studio privat."];
  if(slug==="storage-functional-trainer")return [`${name} menggabungkan latihan kabel dan penyimpanan. Buyer menentukan item yang disimpan, jumlah, ukuran, berat, tinggi pengambilan, serta kemungkinan benturan dengan kabel atau pengguna. Peg, tray, hook, dan holder harus muncul dalam drawing serta daftar pasokan.`,"Nilai produk dari alur mengambil, menggunakan, dan mengembalikan aksesori saat stasiun sibuk. Penyimpanan yang terlihat banyak tetapi menghalangi pulley, maintenance, atau jalur berjalan tidak memberi nilai operasional pada gym komersial."];
  if(/multi-jungle|station-functional/.test(slug))return [`${name} dipilih berdasarkan fungsi setiap stasiun dan jumlah pengguna yang benar-benar dapat berlatih bersamaan. Buyer menamai setiap posisi, tower, seat, handle, dan attachment; angka stasiun tanpa diagram tidak cukup.`,"Simulasikan antrean, perpindahan, pergantian attachment, akses teknisi, serta dampak satu komponen bersama bila mengalami gangguan. Kapasitas pada jam sibuk harus sebanding dengan area, biaya, dan kompleksitas perawatan."];
  if(/bench/.test(slug))return [`${name} dinilai dalam posisi aktual bersama rack dan dumbbell yang akan dipakai. Buyer memeriksa masuk-keluar pengguna, spotter, roda, handle, kaki, gap pad, tinggi datar, serta clearance pada uprights.`,"Ruang penyimpanan dan radius putar perlu masuk layout. Sebuah bench dapat memiliki footprint kecil saat diam tetapi membutuhkan koridor lebih besar ketika dipindah, diatur, atau digunakan dengan barbell."];
  if(/smith/.test(slug))return [`${name} memerlukan koordinasi jalur bar, safety, rack point, kabel bila ada, plate storage, bench, dan ruang pengguna. Setiap fungsi harus diuji tanpa konflik dengan modul lain.`,"Buyer memverifikasi tinggi, lebar, akses masuk, lantai, perakitan, urutan pengencangan, dan prosedur commissioning. Nama Smith tidak menjelaskan counterbalance, guide, stop, atau konfigurasi attachment yang ditawarkan."];
  if(/rack|frame/.test(slug))return [`${name} ditempatkan berdasarkan latihan utama, tinggi bar, posisi safety, bench, plate loading, penyimpanan, dan jalur spotter. Drawing proyek perlu menunjukkan area dinamis, bukan hanya ukuran luar rangka.`,"Titik sambung, hardware, stabilitas, anchor bila diperlukan, perlindungan lantai, dan inspeksi setelah perakitan menjadi bagian pengadaan. Aksesori hanya dinyatakan kompatibel setelah interface serta konfigurasi diperiksa."];
  if(/cable|trainer|machine/.test(slug))return [`${name} dinilai dari range gerak, posisi adjustment, rasio atau resistansi yang ditawarkan, jalur kabel, pulley, guard, attachment, dan akses ke komponen aus. Buyer memetakan envelope kabel bersama posisi pengguna.`,"Maintenance memerlukan identifikasi kabel, bearing atau pulley, prosedur tension, dan ruang kerja teknisi. Menempatkan unit terlalu dekat dinding atau mesin lain dapat mengurangi fungsi meskipun bodi fisiknya muat."];
  if(/dumbbell/.test(slug))return [`${name} harus dilihat sebagai bagian dari satu set. Buyer memetakan rentang berat, increment, pasangan ganda, panjang rak, posisi marking, dan penggantian satu SKU agar lineup tetap rapi.`,"Periksa unit ringan, menengah, dan berat karena diameter, panjang, kepala, grip, serta karton dapat berubah. Sampel satu berat tidak otomatis membuktikan seluruh rentang atau utilisasi pallet."];
  if(/plate/.test(slug))return [`${name} perlu cocok dengan bar, sleeve, mesin, storage peg, dan aturan penggunaan fasilitas. Buyer membandingkan lubang, insert, ketebalan, diameter, grip, marking, serta jumlah plate yang muat pada penyimpanan.`,"Susun set berdasarkan kebutuhan loading dan ruang, bukan hanya berat total. Plate yang lebih tebal dapat membatasi kapasitas sleeve; plate logam yang tipis memiliki perilaku lantai serta kebisingan berbeda dari konstruksi berlapis."];
  if(/kettlebell/.test(slug))return [`${name} dinilai sebagai seri berat dengan geometri handle dan bidang dasar yang konsisten. Buyer menguji grip satu atau dua tangan, rack position, marking, stabilitas, dan jarak pada rak.`,"Ukuran badan dan handle dapat berubah menurut berat. Gunakan beberapa titik seri untuk approval agar tampilan, ergonomi, dan kemasan tidak disimpulkan dari satu unit saja."];
  return [`${name} ditempatkan dalam assortment berdasarkan fungsi, target pelanggan, unit penjualan, display, penyimpanan, dan kecepatan repeat order. Buyer menetapkan alasan komersial setiap varian sebelum menambahkannya ke RFQ.`,"Periksa interface, finishing, identifikasi, aksesori, karton, dan cara pelanggan menggunakan produk. Varian yang serupa harus memiliki pembeda yang dapat dijelaskan, diukur, serta dipertahankan antarbatch."];
}

function specialProductBlocks(source:string,name:string){
  if(source==="tpu-dumbbell-kg")return[
    idAnswer("jawaban-cepat-khusus","Jawaban cepat",`${name} cocok untuk buyer yang menempatkan konsistensi permukaan, warna, kebersihan, dan identitas seri sebagai bagian penting dari nilai produk. Keputusan tidak cukup berdasarkan label TPU: minta konstruksi per komponen, sampel beberapa berat, referensi warna, metode marking, hasil pembersihan, serta batas cacat visual yang dapat diterapkan pada batch.`),
    idDefinition("definisi-khusus",`Apa itu ${name}?`,`${name} adalah dumbbell dengan bagian luar berbasis TPU pada konfigurasi yang disetujui, dipadukan dengan inti, handle, sambungan, dan marking tertentu. TPU bukan uraian lengkap produk. Drawing dan bill of materials harus menjelaskan area yang memakai TPU, sistem ikatan, geometri kepala, profil grip, angka berat, serta bagian yang tetap logam.`),
    idText("arsitektur-seri-tpu","Arsitektur seri TPU",`Susun rentang berat sebagai satu keluarga visual. Periksa perubahan diameter kepala, panjang keseluruhan, ruang jari, orientasi logo, ukuran angka, dan jarak pada rack untuk berat ringan, menengah, serta berat. Buyer distributor juga perlu menentukan apakah SKU dijual per unit, pasangan, set, atau paket dengan rack.`,`Konsistensi seri lebih bernilai daripada sampel tunggal yang terlihat baik. Approval memakai beberapa titik berat dan mencatat bagian yang boleh berubah karena geometri internal. Foto lineup, drawing per SKU, dan daftar berat membantu tim pemasaran serta gudang menjaga identitas yang sama.`),
    idText("uji-permukaan-tpu","Pemeriksaan permukaan dan perawatan",`Rencana QC TPU perlu menyebut kebersihan mould line, tepi, rongga, noda, perbedaan kilap, transfer warna, ketajaman marking, dan kondisi setelah penanganan. Gunakan pencahayaan, jarak pandang, area inspeksi, dan referensi sampel yang disepakati agar istilah mulus atau premium tidak subjektif.`,`Simulasikan pembersihan dengan prosedur yang realistis untuk fasilitas target tanpa mengklaim kompatibilitas bahan kimia yang belum diuji. Catat perubahan tekstur, warna, marking, atau adhesi. Instruksi perawatan untuk pelanggan harus mengikuti hasil aktual dan tidak menjanjikan ketahanan universal.`),
    idText("pembelian-tpu","Keputusan komersial untuk lini TPU",`Buyer membandingkan TPU dengan rubber, PU, atau material lain pada konstruksi nyata, bukan nama resin saja. Nilai yang ditinjau mencakup tampilan, sentuhan, bau, pembersihan, stabilitas warna, pilihan logo, konsistensi batch, biaya, karton, dan posisi harga di pasar Indonesia.`,`Untuk RFQ, kirim rentang berat, jumlah setiap SKU, preferensi warna, layout marking, metode logo, tipe rack, dan channel penjualan. Minta supplier memisahkan biaya standar, perubahan warna, tooling, sampel, karton, serta minimum proses sehingga strategi assortment dapat dihitung.`),
    idTable("perbandingan-tpu","Perbandingan keputusan TPU",["Area","Data sampel","Keputusan batch"],[["Permukaan","Tekstur, kilap, mould line","Batas visual"],["Warna","Referensi dan pencahayaan","Rentang diterima"],["Marking","Metode dan keterbacaan","Posisi serta ketahanan"],["Seri","Titik berat dan rack","Konsistensi lineup"],["Perawatan","Prosedur yang diuji","Instruksi pelanggan"]]),
    idChecklist("checklist-tpu","Checklist buyer untuk dumbbell TPU",["Tentukan area produk yang memakai TPU","Pilih titik berat untuk sampel seri","Setujui tekstur, kilap, warna, dan mould line","Ukur ruang grip dan kecocokan rack","Verifikasi marking pada berat ringan dan berat","Catat prosedur pembersihan yang diuji","Pisahkan MOQ warna, logo, dan setiap SKU","Periksa perlindungan kepala di dalam karton","Simpan referensi warna serta revisi artwork","Bandingkan repeat order dengan sampel terkontrol"])
  ];
  if(source==="cpu-compact-dumbbell")return[
    idAnswer("jawaban-cepat-khusus","Jawaban cepat",`${name} ditujukan untuk lineup yang membutuhkan jejak penyimpanan ringkas tanpa mengorbankan ruang tangan, pembacaan berat, dan identitas SKU. Buyer harus menguji geometri kepala CPU, panjang handle, jarak antarunit di rack, stabilitas saat diletakkan, serta kemasan per berat sebelum menilai kepadatan set.`),
    idDefinition("definisi-khusus",`Apa itu ${name}?`,`${name} adalah dumbbell berlapis CPU dengan proporsi kepala yang dirancang ringkas pada konfigurasi tertentu. Kata kompak harus dibuktikan melalui drawing, dimensi per berat, panjang keseluruhan, area grip, dan jumlah unit yang dapat ditempatkan pada rack; bukan sekadar kesan dari foto katalog.`),
    idText("geometri-kompak","Geometri, grip, dan rack",`Ukur diameter atau envelope kepala, panjang kepala, lebar grip, panjang keseluruhan, serta clearance jari. Lakukan pemeriksaan pada berat ringan, tengah, dan berat karena perubahan inti dapat mengubah proporsi. Letakkan pasangan bersebelahan untuk melihat apakah tangan dapat mengambil unit tanpa menyentuh kepala lain.`,`Cocokkan seri dengan saddle atau tray rack yang benar. Catat orientasi dumbbell, jarak pusat, tinggi pengambilan, kapasitas setiap tingkat, dan risiko rolling. Klaim hemat ruang hanya dapat dibuat setelah lineup aktual dipetakan pada rack serta area sirkulasi fasilitas.`),
    idText("qc-cpu-kompak","QC khusus konstruksi CPU kompak",`Periksa pengisian di sekitar inti, simetri kepala, garis mould, sudut, tepi, posisi handle, centering, marking berat, dan kestabilan pada permukaan datar. Batas visual perlu dibedakan dari cacat yang memengaruhi fungsi, agar keputusan penerimaan tidak berubah antarinspektur.`,`Timbang dan ukur setiap titik seri sesuai rencana sampling yang disetujui. Jika tooling atau inti berbeda menurut berat, laporan harus mengidentifikasi cavity, model, dan revisi. Data tersebut membantu mencari penyebab bila satu SKU menyimpang sementara SKU lain tetap sesuai.`),
    idText("assortment-kompak","Menyusun assortment kompak",`Distributor dapat memilih rentang penuh, titik berat utama, atau paket menurut segmen pelanggan. Hitung jumlah pasangan, ruang rack, unit pengganti, bobot pengiriman, dan kecepatan rotasi per SKU. Jangan menambah semua increment bila pasar, ruang, atau modal kerja tidak mendukung.`,`Brief merek sendiri mencantumkan posisi logo pada kepala yang lebih kecil, keterbacaan angka, kontras warna, dan foto listing. Sampel kemasan perlu memastikan kepala tidak saling menekan, handle terlindungi, label mudah dipindai, dan karton dapat ditangani sesuai beratnya.`),
    idTable("perbandingan-kompak","Perbandingan konfigurasi kompak",["Area","Pertanyaan","Bukti"],[["Dimensi","Seberapa ringkas per berat?","Drawing lineup"],["Grip","Apakah tangan memiliki clearance?","Uji pengguna"],["Rack","Berapa pasangan per tingkat?","Layout aktual"],["Marking","Apakah angka tetap terbaca?","Sampel beberapa berat"],["Kemasan","Apakah kepala terlindungi?","Drop/handling plan"]]),
    idChecklist("checklist-cpu-kompak","Checklist buyer untuk dumbbell CPU kompak",["Minta dimensi per titik berat","Ukur clearance tangan dan lebar grip","Uji kecocokan pada rack yang dipilih","Periksa stabilitas ketika unit diletakkan","Setujui marking yang tetap terbaca","Identifikasi tooling atau inti per kelompok berat","Hitung kapasitas set dan kebutuhan pengganti","Validasi karton menurut pusat massa","Pisahkan MOQ per berat, logo, dan warna","Arsipkan drawing lineup untuk repeat order"])
  ];
  return[];
}

function productVersion(entity:ContentEntity):LocalizedContentVersion{
  const name=productName(entity),source=sourceSlug(entity),slug=slugify(name),group=family(entity),path=`/id/produk/${group}/${slug}`,images=sourceImages(entity,slug);
  const category=group==="dumbbell"?"Dumbbell":group==="piring-beban"?"Piring beban":group==="rak-bangku"?"Rack dan bench":"Aksesori gym";
  const body=[
    idAnswer("jawaban-cepat","Jawaban cepat",`${name} ditujukan untuk gym, distributor, importir, dan brand yang membutuhkan spesifikasi berulang, data produk jelas, kontrol batch, serta pilihan OEM. Buyer perlu membandingkan penggunaan, konstruksi, varian, sampel, QC, kemasan, dan landed cost; harga satuan saja tidak cukup.`),
    idDefinition("definisi",name,`${name} adalah bagian dari kategori ${category.toLowerCase()} untuk pengadaan profesional. Identitas produk harus menghubungkan kode, bahan, berat atau kapasitas, ukuran, fungsi, finishing, marking, karton, dan revisi yang sama dari sampel sampai repeat order.`),
    idText("posisi-pasar","Posisi produk dan penggunaan",`${name} dapat dipertimbangkan untuk gym komersial, studio, hotel, fasilitas perusahaan, proyek apartemen, distributor, importir, atau lini merek sendiri sesuai konfigurasi yang disetujui. Frekuensi penggunaan, profil pengguna, ruang, penyimpanan, pembersihan, dan akses servis menentukan apakah versi tertentu sesuai.`,`Pemilik gym menilai kenyamanan, kestabilan, perawatan, dan waktu henti. Distributor menilai struktur SKU, tampilan, karton, pallet, spare part, dan repeat order. Brand juga perlu menjaga konsistensi logo, warna, label, foto, dan data produk pada kanal penjualannya.`),
    idTable("tabel-spesifikasi","Tabel spesifikasi yang harus dikonfirmasi",["Bagian","Data pesanan","Bukti"],[["Model",name,"Kode artikel, revisi, dan gambar"],["Material","Per komponen kritis","Deklarasi atau spesifikasi yang disepakati"],["Berat / kapasitas","Per SKU dan metode","Sampel serta catatan inspeksi"],["Ukuran","Nilai dan toleransi per varian","Gambar serta pemeriksaan dimensi"],["Finishing","Warna, tekstur, dan batas visual","Sampel fisik yang disetujui"],["Logo","Metode, posisi, ukuran","Artwork dan sampel"],["Kemasan","Unit per karton dan perlindungan","Sampel karton serta packing list"]],"Nilai akhir mengikuti SKU dan penawaran yang disetujui; halaman ini tidak membuat angka generik untuk semua model."),
    idText("material","Material dan konstruksi",materialText(source,name),`Mintalah supplier menjelaskan bagian mana yang memakai bahan tersebut, proses pembentukan atau sambungan, permukaan yang bersentuhan dengan pengguna, lantai, bar, rack, atau produk lain, serta variasi yang dianggap dapat diterima. Catatan ini menjadi dasar sampel dan pemeriksaan batch.`),
    idText("geometri","Berat, ukuran, dan fungsi",geometryText(source,name),`Berat bersih, berat kotor, ukuran produk, area operasi, dan ukuran karton harus dikonfirmasi untuk konfigurasi yang ditawarkan. Buyer tidak boleh memakai data dari foto, keluarga produk lain, atau sampel dengan revisi berbeda sebagai spesifikasi pesanan.`),
    idText("aplikasi-spesifik",`Aplikasi khusus ${name}`,...productSpecificAngle(source,name)),
    idText("pembeda-sku",`Pembeda SKU ${name}`,`${name} harus mempunyai alasan yang jelas untuk berada dalam lini ${category.toLowerCase()}. Catat target pengguna ${name}, perbedaan konstruksi ${name}, varian yang ditawarkan, dan masalah yang diselesaikan dibanding SKU terdekat. Bila perbedaan hanya nama atau warna tanpa nilai bagi buyer, jangan menambah kerumitan stok.`,`Saat meminta ${name}, buyer menuliskan kode, rentang, bahan, geometri, marking, unit penjualan, karton, dan hubungan dengan produk pelengkap. Data khusus ${name} tersebut dipakai oleh tim penjualan, QC, gudang, dan repeat order sehingga identitas SKU tidak bergantung pada foto katalog.`),
    uniqueNotes(source,name),
    idText("produksi","Proses produksi",`Alur ${name.toLowerCase()} dimulai dari konfirmasi spesifikasi, material, komponen, dan sampel. Tahap berikutnya dapat mencakup pembentukan, casting, machining, welding, pelapisan, perakitan, marking, dan finishing sesuai konstruksi. Tidak semua tahap berlaku untuk setiap model.`,`Bill of materials, gambar, instruksi kerja, artwork, dan sampel harus memiliki revisi yang selaras. Perubahan material, tooling, sub-supplier, proses, atau kemasan yang berpotensi mengubah fungsi dan tampilan perlu dilaporkan sebelum produksi dilanjutkan.`),
    idText("kontrol-kualitas","Kontrol kualitas dan penerimaan",`Incoming inspection memeriksa material serta komponen teridentifikasi. Pemeriksaan proses menangkap deviasi sebelum produk selesai. Final inspection memeriksa identitas, jumlah, berat atau kapasitas, ukuran, fungsi, permukaan, marking, aksesori, karton, dan pallet berdasarkan rencana sampling.`,`Setiap hasil harus terhubung dengan kriteria, metode, alat, unit yang diperiksa, dan laporan. Ketidaksesuaian diklasifikasikan berdasarkan risiko dan ditangani melalui pemisahan, rework, penggantian, atau pemeriksaan ulang sebelum izin pengiriman.`),
    idTable("perbandingan","Perbandingan jalur pembelian",["Pilihan","Cocok untuk","Hal yang dikontrol"],[["Versi standar","Peluncuran cepat dan spesifikasi mapan","Cakupan, ketersediaan, dan konsistensi"],["Logo kustom","Merek sendiri tanpa perubahan struktur","Metode, ketahanan, posisi, dan MOQ"],["Warna kustom","Lini terkoordinasi atau proyek khusus","Referensi warna dan variasi"],["ODM","Perubahan fungsi atau geometri","Gambar, tooling, uji, dan kepemilikan file"],["Kemasan retail","Distribusi melalui toko atau marketplace","Label, barcode, bahasa, dan kekuatan logistik"]]),
    idText("kemasan","Pengemasan dan pengiriman ke Indonesia",`Produk berat atau besar membutuhkan kemasan yang sesuai dengan pusat massa, cara angkat, penumpukan, kelembapan, dan rute. Pelindung internal mencegah kontak dan pergerakan; karton mengidentifikasi kode, varian, jumlah, berat bersih, serta berat kotor.`,`Packing list harus cocok dengan unit, karton, dan pallet fisik. Importir menentukan pelabuhan atau alamat, Incoterm beserta named place, kebutuhan asuransi, customs clearance, bongkar, dan pengiriman domestik. Ketentuan Indonesia harus diverifikasi untuk transaksi aktual.`),
    idText("oem-odm","OEM, ODM, logo, dan kustomisasi",`Kustomisasi ${name.toLowerCase()} dapat meliputi logo, warna, marking berat, label, manual, barcode, dan karton; kelayakan bergantung pada bahan, proses, dan volume. Perubahan struktur atau tooling diperlakukan sebagai proyek ODM dengan evaluasi teknis terpisah.`,`MOQ dapat berbeda menurut produk, warna, logo, bahan, dan kemasan. Buyer sebaiknya mengirim jumlah per SKU dan memisahkan kebutuhan wajib dari opsi. Artwork dan sampel disetujui sebelum material untuk produksi massal dilepas.`),
    idText("pengadaan-b2b","Informasi pengadaan B2B",`RFQ ${name.toLowerCase()} yang efektif memuat jumlah per varian, penggunaan, target pelanggan, negara tujuan, logo, warna, kemasan, jadwal, dan syarat yang tidak dapat diubah. Untuk satu seri, tandai SKU inti, SKU pelengkap, pasangan ganda, serta spare part.`,`Sampel perlu memiliki tujuan jelas: tampilan, fungsi, produksi, atau kombinasi. Laporan persetujuan mencatat ukuran, foto, hasil fungsi, deviasi yang diterima, dan poin terbuka agar buyer tidak memberi persetujuan umum pada versi yang belum terdefinisi.`),
    idChecklist("checklist","Checklist pembelian",["Konfirmasi model, penggunaan, dan target pelanggan","Tentukan varian, berat, kapasitas, atau ukuran","Definisikan bahan setiap komponen kritis","Tulis toleransi dan metode pemeriksaan","Setujui finishing, warna, marking, dan logo","Konfirmasi MOQ per varian dan proses","Periksa unit per karton, label, barcode, dan pallet","Minta berat bersih, berat kotor, serta volume","Tentukan inspeksi pra-pengiriman dan tindakan cacat","Arsipkan revisi untuk repeat order"]),
    uniqueNotes([...source].reverse().join(""),name,"verifikasi-khusus"),
    idText("pengalaman-pabrik","Informasi langsung dari proses pabrik",`Dalam pengalaman produksi PowerBaseFit, masalah terlambat sering berawal dari detail yang belum dibekukan: kg dan lb, posisi logo, rona warna, aksesori yang dianggap termasuk, arah produk di karton, atau revisi drawing. Review praproduksi menghubungkan semua detail tersebut.`,`Sampel menunjukkan bahwa satu versi dapat dibuat; kontrol batch menunjukkan kemampuan mengulangnya. Foto dan video membantu review, tetapi pengukuran, kriteria, identitas unit, serta catatan inspeksi yang memungkinkan keputusan dapat dipertanggungjawabkan.`),
    idText("permintaan-penawaran","Cara meminta penawaran",`Kirim nama ${name}, jumlah per SKU, kebutuhan logo atau warna, kemasan, tujuan Indonesia, Incoterm, serta jadwal. PowerBaseFit akan menilai kelayakan, MOQ, harga, sampel, lead time, dan rencana QC berdasarkan konfigurasi tersebut.`,`Bandingkan penawaran dengan scope yang sama. Harga yang lebih rendah dapat belum memasukkan artwork, tooling, karton, pallet, aksesori, spare part, inspeksi, atau transportasi. Semua asumsi harus terlihat sebelum supplier dipilih.`)
  ];
  const replaced=new Set(["posisi-pasar","produksi","kontrol-kualitas","kemasan","oem-odm","pengadaan-b2b","pengalaman-pabrik","permintaan-penawaran"]);
  let localizedBody=body.filter((block)=>!replaced.has(block.id));
  const special=specialProductBlocks(source,name);
  if(special.length){const replaceSpecial=new Set(["jawaban-cepat","definisi","pembeda-sku","perbandingan","catatan-khusus","verifikasi-khusus"]);localizedBody=[...special,...localizedBody.filter((block)=>!replaceSpecial.has(block.id))];}
  localizedBody.splice(7,0,...distinctBlocks(source,name),...extraDistinctBlocks(source,name,"pendalaman",1));
  return base({slug,publicPath:path,title:`${name} | Produsen OEM PowerBaseFit`,description:`${name} untuk gym dan distributor: material, spesifikasi, produksi, QC, kemasan ekspor, OEM, ODM, logo, dan penawaran B2B.`,h1:`${name} untuk gym profesional dan pengadaan B2B`,body:localizedBody,faq:[{id:"faq-1",question:`Berapa MOQ untuk ${name.toLowerCase()}?`,answer:"MOQ bergantung pada model, varian, bahan, logo, dan kemasan; nilainya dikonfirmasi setelah brief proyek."},{id:"faq-2",question:"Apakah perlu menyetujui sampel?",answer:"Ya bila material, fungsi, finishing, logo, atau karton memengaruhi hasil. Catat revisi dan kriteria persetujuannya."},{id:"faq-3",question:"Bagaimana kualitas batch diperiksa?",answer:"Melalui incoming inspection, pemeriksaan selama proses, dan final inspection terhadap identitas, ukuran, fungsi, permukaan, marking, serta kemasan berdasarkan rencana yang disepakati."},{id:"faq-4",question:"Apakah produk dapat memakai merek sendiri?",answer:"Dapat untuk konfigurasi dan volume yang sesuai. Metode, artwork, posisi, ketahanan, MOQ, dan sampel dikonfirmasi sebelum produksi."},{id:"faq-5",question:"Data apa yang diperlukan untuk harga?",answer:"Kirim jumlah per varian, penggunaan, kustomisasi, kemasan, tujuan, Incoterm, dan jadwal agar penawaran dapat dihitung serta dibandingkan."}],author:indonesianEditorialAuthor,reviewedBy:indonesianTechnicalReviewer,schemaData:{sku:entity.versions.en?.schemaData.sku??`PBF-${source.toUpperCase()}`,brand:"PowerBaseFit",manufacturer:"PowerBaseFit",material:materialText(source,name).split(".")[0],category,specifications:[{name:"Produk",value:name},{name:"Varian",value:"Sesuai SKU dan penawaran yang disetujui"},{name:"Berat dan ukuran",value:"Dikonfirmasi per konfigurasi pada drawing dan packing list"},{name:"Tujuan",value:"Gym, distributor, importir, dan merek fitness"}],breadcrumbs:[{name:"Beranda",path:"/id"},{name:"Produk",path:"/id/produk"},{name:category,path:`/id/produk/${group}`},{name,path}],extra:{primaryKeyword:`${name.toLowerCase()} profesional`,searchIntent:"evaluasi produk, supplier, dan permintaan penawaran B2B"}},images,internalLinks:[{targetContentId:group==="dumbbell"?"dumbbells-category":group==="piring-beban"?"weight-plates-category":group==="rak-bangku"?"racks-benches-category":"gym-accessories-category",label:"Lihat kategori produk"},{targetContentId:"factory",label:"Pelajari produksi dan kontrol kualitas"},{targetContentId:"oem-private-label",label:"Tinjau OEM dan merek sendiri"},{targetContentId:"contact",label:"Minta penawaran B2B"}]});
}

function coreVersion(entity:ContentEntity,profile:CoreProfile):LocalizedContentVersion{
  const first=entity.versions.en?.images[0]?.src??"/assets/hero-poster.avif";
  const images=[first,"/assets/dumbbell-production.webp","/assets/factory-cases/packaging-area-pbf.webp"].map((src,index)=>({id:`gambar-${index+1}`,src:indonesianImagePath(src,slugify(profile.keyword),index),alt:index===0?`${profile.h1} PowerBaseFit`:index===1?`Proses produksi nyata peralatan gym PowerBaseFit`:`Area kemasan ekspor nyata di pabrik PowerBaseFit`,caption:index===0?"Aset nyata PowerBaseFit yang berkaitan dengan halaman ini.":index===1?"Proses produksi harus mengikuti spesifikasi dan revisi produk yang disetujui.":"Kemasan dan packing list diperiksa sebelum barang dikirim."}));
  const body=[idAnswer("jawaban","Jawaban cepat",`${profile.h1}. Halaman ini membantu buyer Indonesia untuk ${profile.role} dengan data yang dapat dimasukkan ke RFQ, sampel, QC, kemasan, dan keputusan pengadaan.`),idDefinition("definisi",profile.keyword,`${profile.keyword} dalam konteks PowerBaseFit berarti layanan manufaktur dan pasokan B2B yang menghubungkan produk nyata, spesifikasi, kontrol mutu, kustomisasi, serta dokumen pesanan; bukan klaim umum tanpa model atau bukti.`),idText("fokus","Fokus halaman",profile.focus,`Buyer perlu memisahkan fakta produk, nilai yang masih harus dikonfirmasi, dan tanggung jawab di Indonesia. PowerBaseFit menyediakan informasi produksi dan ekspor; importir serta profesional setempat menentukan klasifikasi, perizinan, instalasi, pajak, dan kewajiban yang berlaku.`),idTable("alur","Alur keputusan B2B",["Tahap","Data utama","Hasil"],[["Kebutuhan","Pengguna, pasar, produk, jumlah","Brief"],["Spesifikasi","Bahan, ukuran, fungsi, tampilan","RFQ"],["Validasi","Sampel, artwork, metode uji","Versi disetujui"],["Produksi","Revisi, proses, pemeriksaan","Batch teridentifikasi"],["Pengiriman","Karton, pallet, Incoterm, tujuan","Packing list dan dokumen"]]),idText("supplier","Menilai produsen dan penawaran",`Penawaran harus menyebut SKU, jumlah per varian, bahan, konfigurasi, logo, kemasan, MOQ, sampel, lead time, QC, Incoterm, dan named place. Sel yang kosong dianggap pertanyaan terbuka, bukan otomatis termasuk.`,`Buyer dapat meminta bukti yang berkaitan dengan produk nyata: drawing, sampel, catatan ukuran, foto proses, laporan inspeksi, identifikasi karton, atau packing list. Bukti generik tidak menggantikan data untuk SKU yang dibeli.`),idText("pasar-indonesia","Konteks pembelian Indonesia","Pasar Indonesia memakai istilah alat fitness, peralatan gym komersial, distributor, importir, supplier, pabrik, grosir, dan minta penawaran. Istilah Inggris seperti dumbbell, bumper plate, power rack, OEM, ODM, MOQ, dan private label tetap digunakan ketika sudah lazim dalam perdagangan.","Kondisi pelabuhan, perizinan, HS code, bea, pajak, standar, label, instalasi, dan pengiriman domestik dapat berbeda menurut barang dan transaksi. Verifikasi aktual dilakukan oleh importir, customs broker, freight forwarder, atau pihak berwenang yang kompeten."),idText("kualitas","Kualitas dan bukti","Kualitas didefinisikan melalui spesifikasi, metode pemeriksaan, batas penerimaan, sampling, dan tindakan bila hasil tidak sesuai. Pernyataan seperti heavy-duty, commercial grade, atau premium perlu diterjemahkan menjadi bahan, geometri, fungsi, pengujian, dan dokumentasi.","Sampel tidak otomatis mewakili batch bila revisi, material, tooling, atau proses berubah. Identifikasi versi dan change control menjaga hubungan antara persetujuan awal, produksi, inspeksi akhir, dan repeat order."),idText("oem","OEM, ODM, dan merek sendiri","Logo, warna, marking, label, dan karton dapat dinilai sebagai kustomisasi identitas. Perubahan struktur, fungsi, mould, atau tooling memerlukan jalur pengembangan, sampel, pengujian, biaya, dan waktu yang berbeda.","MOQ dihitung menurut produk dan proses. Buyer sebaiknya mengirim daftar SKU serta volume yang realistis sehingga supplier dapat memisahkan pilihan standar, private label, dan pengembangan ODM."),idChecklist("checklist","Checklist sebelum menghubungi supplier",["Tentukan tipe buyer dan pasar penjualan","Susun produk serta jumlah per SKU","Jelaskan penggunaan dan tingkat pemakaian","Pisahkan persyaratan wajib dan opsi","Tentukan kebutuhan logo, warna, dan kemasan","Kirim tujuan dan Incoterm yang diinginkan","Minta data berat, volume, karton, dan pallet","Rencanakan sampel serta inspeksi","Verifikasi tanggung jawab impor di Indonesia","Simpan revisi untuk repeat order"]),uniqueNotes(entity.id,profile.keyword),idText("tindakan","Langkah berikutnya",`Siapkan brief yang menyebut ${profile.keyword}, produk, jumlah, target pelanggan, kustomisasi, tujuan, dan jadwal. PowerBaseFit akan menandai data yang memengaruhi kelayakan, MOQ, sampel, harga, QC, serta pengiriman.`,`Jika informasi kritis belum tersedia, langkah yang benar dapat berupa klarifikasi teknis atau sampel, bukan harga prematur. Urutan tersebut mengurangi revisi, biaya tersembunyi, dan perbandingan penawaran yang tidak setara.`)];
  const faq=[{id:"faq-1",question:`Apa langkah pertama untuk ${profile.keyword}?`,answer:"Tetapkan kebutuhan bisnis, pengguna, produk, jumlah, tujuan, dan keputusan yang perlu dibuat sebelum meminta harga."},{id:"faq-2",question:"Apakah PowerBaseFit melayani OEM dan private label?",answer:"Ya untuk produk, proses, dan volume yang sesuai. Kelayakan, MOQ, artwork, sampel, QC, serta kemasan dikonfirmasi per proyek."},{id:"faq-3",question:"Bagaimana cara membandingkan supplier?",answer:"Kirim RFQ yang sama dan bandingkan scope yang sama: spesifikasi, jumlah, sampel, kustomisasi, QC, kemasan, Incoterm, dan pengecualian."},{id:"faq-4",question:"Siapa yang memeriksa aturan impor Indonesia?",answer:"Importir dan profesional terkait memverifikasi klasifikasi, dokumen, perizinan, bea, pajak, serta kewajiban yang berlaku untuk transaksi aktual."},{id:"faq-5",question:"Data apa yang harus dikirim untuk penawaran?",answer:"Produk, jumlah per varian, penggunaan, logo, warna, kemasan, tujuan, Incoterm, jadwal, dan persyaratan wajib."}];
  return base({slug:profile.path.split("/").filter(Boolean).pop()||"id",publicPath:profile.path,title:profile.title,description:profile.description,h1:profile.h1,body,faq,author:indonesianEditorialAuthor,reviewedBy:indonesianTechnicalReviewer,schemaData:{brand:"PowerBaseFit",manufacturer:"PowerBaseFit",category:"Peralatan gym profesional",specifications:[{name:"Topik",value:profile.keyword},{name:"Tujuan",value:profile.role}],breadcrumbs:[{name:"Beranda",path:"/id"},{name:profile.h1,path:profile.path}],extra:{primaryKeyword:profile.keyword,searchIntent:profile.role}},images,internalLinks:entity.id==="contact"?[]:[{targetContentId:"products-hub",label:"Jelajahi produk"},{targetContentId:"factory",label:"Lihat proses pabrik"},{targetContentId:"oem-private-label",label:"Pelajari OEM dan merek sendiri"},{targetContentId:"contact",label:"Minta penawaran"}]});
}

function specialGuideBlocks(id:string){
  if(id==="moq-guide")return[
    idAnswer("jawaban-moq","Jawaban cepat",`MOQ peralatan fitness bukan satu angka untuk seluruh purchase order. Minimum dapat berasal dari model, berat, warna, compound, mould, logo, label, karton, atau jadwal produksi. Buyer Indonesia perlu meminta minimum per proses dan per SKU, lalu menyusun assortment yang memenuhi batas produksi tanpa menciptakan stok lambat.`),
    idDefinition("definisi-moq","Definisi MOQ dalam pengadaan gym",`MOQ atau minimum order quantity adalah jumlah terendah yang dapat ditawarkan pada kondisi biaya, material, proses, dan konfigurasi tertentu. MOQ produk standar dapat berbeda dari minimum custom color, printing, mould, atau packaging. Karena itu quotation harus menyebut satuan, tingkat penerapan, dan asumsi di balik setiap minimum.`),
    idText("lapisan-moq","Memetakan lapisan MOQ",`Mulai dari satu baris per SKU. Tambahkan kolom minimum model, minimum berat, minimum warna, minimum logo, isi karton, jumlah per pallet, dan minimum bahan. Sebuah order besar masih dapat gagal memenuhi minimum apabila volumenya tersebar ke terlalu banyak kombinasi.`,`Tandai proses yang menjadi bottleneck. Compound warna mungkin berjalan per batch, karton dicetak per desain, sementara produk standar tersedia lebih fleksibel. Informasi ini membantu buyer menggabungkan SKU secara rasional dan menghindari asumsi bahwa jumlah total otomatis memenuhi semua syarat.`),
    idText("negosiasi-moq","Cara menegosiasikan MOQ tanpa memindahkan risiko",`Negosiasi yang baik mengubah konfigurasi, bukan sekadar meminta angka lebih rendah. Pilihan dapat berupa memakai warna standar, satu artwork untuk beberapa SKU, plain carton dengan label, membatasi titik berat awal, menjadwalkan repeat order, atau membayar biaya setup yang transparan bila layak.`,`Tanyakan konsekuensi setiap opsi pada harga, lead time, konsistensi, sisa material, dan repeat order. MOQ rendah yang disubsidi oleh harga tinggi, setup tersembunyi, atau stok bahan tanpa kepemilikan jelas tidak selalu lebih aman daripada minimum normal.`),
    idTable("skenario-moq","Skenario keputusan MOQ",["Situasi","Pilihan buyer","Data yang diminta"],[["Uji pasar","SKU inti dan tampilan standar","Minimum per SKU dan karton"],["Private label awal","Satu logo, warna standar","Minimum marking dan artwork"],["Warna khusus","Gabungkan SKU yang memakai compound sama","Minimum batch warna"],["Lini penuh","Prioritaskan berat dengan rotasi tinggi","Forecast dan jadwal repeat"],["ODM","Pisahkan tooling dari unit produksi","Biaya setup dan minimum produksi"]]),
    idChecklist("checklist-moq","Checklist negosiasi MOQ",["Minta minimum per SKU dan per proses","Bedakan unit, pasangan, set, karton, dan pallet","Tandai warna atau artwork yang dapat digabung","Pisahkan biaya setup dari harga unit","Hitung stok lambat pada skenario terburuk","Konfirmasi kepemilikan sisa bahan","Tulis validitas harga dan jadwal produksi","Uji opsi standar sebelum meminta custom","Rencanakan repeat order berdasarkan sell-through","Simpan asumsi MOQ pada quotation final"])
  ];
  if(id==="commercial-free-weight-rfq")return[
    idAnswer("jawaban-rfq","Jawaban cepat",`RFQ free weight komersial yang dapat dibandingkan memakai satu baris per SKU dan kolom tetap untuk jumlah, material, berat, ukuran, toleransi, logo, kemasan, QC, Incoterm, serta deviasi. Tujuannya bukan membuat dokumen panjang, melainkan mencegah supplier mengisi bagian kosong dengan asumsi yang berbeda.`),
    idDefinition("definisi-rfq","Apa itu RFQ free weight?",`Request for quotation adalah paket informasi terkontrol yang meminta supplier memberi harga untuk scope yang sama. Pada dumbbell, piring beban, bar, rack, dan aksesori, RFQ menghubungkan kebutuhan komersial dengan kode produk, drawing, metode uji, artwork, packing instruction, jadwal, serta format jawaban.`),
    idText("struktur-rfq","Struktur workbook RFQ",`Buat sheet ringkasan proyek, daftar SKU, spesifikasi teknis, kustomisasi, inspeksi, kemasan, dan logistik. Gunakan identifier yang sama pada semua sheet. Sel wajib diberi status: disetujui, deviasi, perlu klarifikasi, tidak ditawarkan, atau tidak berlaku.`,`Hindari paragraf bebas untuk data yang harus dibandingkan. Berat, ukuran, jumlah, harga, MOQ, lead time, dan volume ditempatkan dalam kolom. Catatan bebas dipakai untuk menjelaskan pengecualian, metode alternatif, atau risiko yang tidak muat dalam struktur tabel.`),
    idText("kontrol-revisi-rfq","Kontrol revisi dan pertanyaan supplier",`Setiap penerbitan RFQ memiliki nomor revisi, tanggal, pemilik, dan daftar perubahan. Supplier menjawab versi yang sama. Pertanyaan dikumpulkan dalam clarification log dengan nomor, tanggal, jawaban, dampak biaya, dan status penutupan.`,`Setelah jawaban diterima, jangan menimpa nilai awal tanpa jejak. Perubahan bahan, jumlah, logo, atau Incoterm dapat mengubah harga dan lead time. Bid comparison harus menunjukkan basis setiap quotation sehingga manajemen mengetahui apakah selisih berasal dari efisiensi atau scope yang berbeda.`),
    idTable("kolom-rfq","Kolom minimum bid comparison",["Kelompok","Kolom wajib","Pemeriksaan"],[["Identitas","SKU, nama, revisi","Sama dengan drawing"],["Komersial","Jumlah, MOQ, harga, mata uang","Scope dan validitas"],["Teknis","Bahan, berat, ukuran, toleransi","Deviasi tertulis"],["Brand","Logo, warna, label, karton","Artwork dan sampel"],["Kualitas","Metode, sampling, laporan","Biaya dan tindakan cacat"],["Logistik","Karton, pallet, Incoterm, tempat","Landed-cost input"]]),
    idChecklist("checklist-rfq-khusus","Checklist sebelum RFQ dikirim",["Tetapkan identifier setiap SKU","Lampirkan drawing atau foto referensi terkontrol","Nyatakan jumlah per unit penjualan","Pisahkan persyaratan wajib dan preferensi","Sediakan kolom deviasi supplier","Nomori artwork dan packing instruction","Tentukan metode QC serta bukti","Minta berat, volume, karton, dan pallet","Sebut Incoterm dan named place","Kunci revisi sebelum bid comparison"])
  ];
  return[];
}

function guideVersion(entity:ContentEntity,profile:GuideProfile):LocalizedContentVersion{
  const path=`/id/blog/${profile.slug}`,first=entity.versions.en?.images[0]?.src??"/assets/resource-cnc-machining.avif";
  const images=[first,"/assets/dumbbell-production.webp","/assets/factory-cases/packaging-area-pbf.webp"].map((src,index)=>({id:`gambar-${index+1}`,src:indonesianImagePath(src,profile.slug,index),alt:index===0?`${profile.h1} untuk buyer Indonesia`:index===1?`Proses produksi nyata terkait ${profile.keyword}`:`Kemasan ekspor nyata untuk pengadaan ${profile.keyword}`,caption:index===0?"Aset nyata PowerBaseFit yang mendukung keputusan pembelian pada panduan ini.":index===1?"Data proses bernilai bila terhubung dengan SKU, revisi, dan kriteria penerimaan.":"Karton, pallet, dan packing list memengaruhi kerusakan serta landed cost."}));
  const body=[idAnswer("jawaban-cepat","Jawaban cepat",`Untuk ${profile.keyword}, mulai dengan tujuan bisnis, penggunaan, volume, dan risiko utama. Bandingkan produk serta supplier menggunakan spesifikasi yang sama, minta bukti yang dapat diverifikasi, lalu hubungkan harga dengan sampel, QC, kemasan, dan biaya tiba.`),idDefinition("definisi",profile.keyword,`${profile.keyword} adalah topik ${profile.intent}. Jawaban yang berguna harus mengubah kebutuhan menjadi data, metode pembandingan, bukti, tanggung jawab, dan keputusan; bukan daftar tips umum.`),idText("sudut-khusus","Analisis khusus",profile.angle,`Terapkan analisis pada SKU atau skenario dengan risiko terbesar. Setelah itu, periksa apakah varian lain benar-benar memakai material, tooling, proses, metode uji, dan kemasan yang sama. Nama seri tidak membuktikan konstruksi identik.`),idTable("matriks","Matriks keputusan",["Area","Pertanyaan","Bukti"],[["Penggunaan","Siapa yang memakai atau menjual?","Profil, fasilitas, frekuensi"],["Produk","Versi mana yang dibeli?","Kode, drawing, bahan, ukuran"],["Kualitas","Apa yang boleh berubah?","Metode, toleransi, sampling"],["Brand","Apa yang dilihat pelanggan?","Artwork, sampel, label, karton"],["Logistik","Bagaimana barang tiba?","Packing list, volume, Incoterm"]]),idText("konteks-indonesia","Konteks buyer Indonesia","Distributor menjaga margin, struktur SKU, repeat order, dan layanan setelah penjualan. Pemilik gym menjaga pengalaman anggota, kapasitas jam sibuk, ruang, perawatan, serta downtime. Brand juga mengontrol identitas visual, data listing, dan konsistensi batch.","Tulis lokasi, channel, target pelanggan, waktu peluncuran, dan volume realistis. Untuk impor, verifikasi klasifikasi, dokumen, izin, bea, pajak, serta kewajiban dengan importir, broker, forwarder, dan sumber resmi yang sesuai transaksi."),idText("metode","Metode kerja",`Pisahkan syarat wajib, preferensi, dan pertanyaan terbuka untuk ${profile.keyword}. Tetapkan pemilik keputusan dan tanggal. Kirim RFQ yang sama kepada supplier dan minta setiap baris ditandai sesuai, menyimpang, atau perlu klarifikasi.`,`Harga dan lead time hanya berarti bila scope sama. Pisahkan produk, logo, warna, sampel, tooling, QC, karton, pallet, freight, asuransi, dan biaya tujuan sehingga pengecualian terlihat sebelum negosiasi.`),idText("perbandingan","Membandingkan alternatif","Buat tabel produk, bahan, ukuran, toleransi, MOQ, sampel, kustomisasi, kontrol, kemasan, Incoterm, dan landed cost. Sel kosong adalah risiko atau asumsi; jangan menganggapnya termasuk.","Spesifikasi tertinggi tidak selalu paling tepat. Pilihan harus memenuhi fungsi, masa pakai, tampilan, perawatan, margin, dan kemampuan stok tanpa menambah berat, biaya, atau variasi yang tidak dihargai pasar."),idText("pengalaman","Pengalaman produsen","PowerBaseFit melihat banyak masalah bermula dari detail kecil: kg dan lb tidak dibedakan, warna tanpa referensi, logo tanpa metode, aksesori dianggap termasuk, atau karton tidak memiliki orientasi. Review teknis harus menutup hal tersebut sebelum material dilepas.","Sampel, pemeriksaan proses, dan final inspection menjawab pertanyaan berbeda. Sampel menetapkan versi; kontrol proses memeriksa kestabilan; inspeksi akhir menilai batch yang siap dikirim."),idText("perhitungan","Jumlah, biaya, dan kapasitas","Tampilkan satuan serta langkah hitung. SKU, unit per SKU, pasangan, berat bersih, berat kotor, volume, pallet, utilisasi kontainer, kerusakan, dan rotasi stok dapat menghasilkan keputusan berbeda dari harga per unit.","Gunakan skenario rendah, dasar, dan tinggi untuk variabel paling tidak pasti. Sensitivity analysis menunjukkan apakah keputusan tetap layak ketika volume, freight, kurs, atau kecepatan penjualan berubah."),idText("uji","Rencana uji dan penerimaan",`Ubah ${profile.keyword} menjadi urutan: persyaratan, metode, alat, sampel, batas, bukti, dan pengambil keputusan. Jika tampilan penting, tentukan cahaya serta referensi; bila ukuran penting, tentukan titik dan satuan; bila fungsi penting, tentukan kondisi uji.`,`Klasifikasikan cacat kritis, mayor, dan minor sesuai penggunaan serta kesepakatan. Untuk hasil di luar batas, tentukan pemisahan, sorting, rework, penggantian, atau inspeksi ulang. Laporan harus mengidentifikasi SKU dan revisi.`),idText("supplier","Menilai supplier dan penawaran",`Minta supplier menjelaskan proses khusus untuk SKU, bukan hanya kemampuan pabrik umum. Periksa siapa yang mengendalikan material, sub-supplier, tooling, sampel, produksi, QC, kemasan, dan perubahan teknis.`,`Normalisasi quotation sebelum memilih. Cantumkan mata uang, masa berlaku, MOQ, lead time, Incoterm beserta named place, scope pengujian, dan biaya satu kali. Selisih harga dapat berasal dari efisiensi atau bagian yang belum dimasukkan.`),idText("pengiriman","Data pengiriman dan repeat order","Arsipkan spesifikasi, sampel, artwork, foto terkontrol, laporan QC, packing instruction, dan packing list. Hubungkan keluhan atau penggantian dengan SKU dan batch supaya data setelah pengiriman memperbaiki RFQ berikutnya.","Sebelum repeat order, tanyakan perubahan material, mould, tooling, warna, sub-supplier, atau kemasan. Bandingkan first article dengan toleransi serta data pesanan sebelumnya untuk mendeteksi pergeseran yang masih tampak sesuai tetapi perlu dipahami."),idChecklist("checklist","Checklist buyer",["Definisikan keputusan, pengguna, dan fasilitas","Daftar SKU serta jumlah per varian","Tulis bahan, ukuran, fungsi, dan toleransi","Minta deviasi secara tertulis","Konfirmasi MOQ dan biaya satu kali","Setujui sampel serta artwork dengan revisi","Tentukan QC, sampling, dan tindakan cacat","Periksa karton, pallet, berat, dan packing list","Bandingkan Incoterm dan named place yang sama","Arsipkan data untuk klaim dan repeat order"]),uniqueNotes(entity.id,profile.keyword),uniqueNotes([...entity.id].reverse().join(""),profile.keyword,"verifikasi-topik"),idText("tindakan","Langkah selanjutnya",`Ubah checklist menjadi RFQ singkat untuk ${profile.keyword}. Lampirkan SKU, jumlah, target pelanggan, kustomisasi, tujuan, dan tanggal yang diinginkan. PowerBaseFit akan menunjukkan hal yang memengaruhi kelayakan, MOQ, sampel, QC, atau pengiriman.`,`Bila persyaratan penting belum jelas, langkah berikutnya dapat berupa diskusi teknis atau rencana sampel, bukan quotation prematur. Urutan ini mengurangi revisi dan perbandingan yang menyesatkan.`),idTable("ringkasan","Ringkasan untuk pengambil keputusan",["Keputusan","Data minimum","Risiko bila tidak ada"],[["Konfigurasi","Versi dan jumlah","Quotation tidak setara"],["Kualitas","Kriteria dan sampel","Perselisihan batch"],["Brand","Artwork dan metode","Produk sulit dijual"],["Logistik","Karton, pallet, Incoterm","Landed cost salah"],["Repeat order","Arsip revisi","Perbedaan antarbatch"]])];
  body.splice(10,0,...distinctBlocks(entity.id,profile.keyword,"panduan"));
  body.splice(17,0,...extraDistinctBlocks(entity.id,profile.keyword,"analisis-lanjutan",3));
  body.splice(6,0,idText("pendalaman-intent",`Pendalaman ${profile.keyword}`,profile.angle,`Dalam topik ${profile.keyword}, buyer perlu menulis keputusan yang diharapkan, data minimum, pihak yang memverifikasi, dan bukti penerimaan. Gunakan ${profile.keyword} sebagai masalah operasional yang memiliki input, metode, output, dan tindakan, bukan sekadar frasa pencarian.`,`Buat contoh dengan SKU, jumlah, tujuan, dan batas waktu yang realistis. Tunjukkan bagaimana perubahan pada material, konfigurasi, MOQ, inspeksi, kemasan, atau freight memengaruhi ${profile.intent}. Dengan demikian pembaca dapat mengadaptasi panduan tanpa menganggap satu jawaban berlaku untuk semua transaksi.`));
  body.splice(8,0,idText("keputusan-topik",`Keputusan khusus untuk ${profile.keyword}`,`${profile.keyword} perlu berakhir pada keputusan yang dapat diaudit. Tulis pilihan yang diterima, alternatif yang ditolak, asumsi, bukti, biaya, risiko, dan pihak yang menyetujui. Bila data ${profile.keyword} berubah, buyer dapat melihat bagian mana dari quotation, sampel, QC, atau landed cost yang harus diperbarui.`,`Gunakan istilah ${profile.keyword} secara konsisten pada brief, tabel perbandingan, komunikasi supplier, dan ringkasan internal. Konsistensi ini membantu importir, distributor, pemilik gym, serta brand membahas masalah yang sama tanpa menyamakan perkiraan, klaim pemasaran, dan data terverifikasi.`));
  const special=specialGuideBlocks(entity.id);const replaceSpecial=new Set(["jawaban-cepat","definisi","matriks","metode","perbandingan","checklist","catatan-khusus","verifikasi-topik"]);const localizedBody=special.length?[...special,...body.filter((block)=>!replaceSpecial.has(block.id))]:body;
  return base({slug:profile.slug,publicPath:path,title:`${profile.title} | PowerBaseFit`,description:`Panduan Indonesia tentang ${profile.keyword}: metode, perbandingan, tabel, checklist, QC, pengadaan, dan pertanyaan untuk supplier.`,h1:profile.h1,body:localizedBody,faq:[{id:"faq-1",question:`Apa langkah pertama untuk ${profile.keyword}?`,answer:"Tentukan tujuan, pengguna, volume, dan keputusan yang perlu dibuat; setelah itu bandingkan produk, supplier, dan harga."},{id:"faq-2",question:"Apakah sampel selalu diperlukan?",answer:"Sampel disarankan bila bahan, ukuran, fungsi, finishing, logo, atau kemasan memengaruhi hasil. Tujuan sampel harus ditulis."},{id:"faq-3",question:"Bagaimana membandingkan dua supplier?",answer:"Gunakan RFQ dan scope yang sama: produk, jumlah, kustomisasi, QC, kemasan, Incoterm, serta biaya yang dikecualikan."},{id:"faq-4",question:"Apakah final inspection menggantikan kontrol proses?",answer:"Tidak. Kontrol proses mencegah dan menemukan deviasi lebih awal; final inspection menilai batch yang sudah selesai."},{id:"faq-5",question:"Siapa yang memverifikasi persyaratan impor?",answer:"Importir dan profesional terkait memeriksa kewajiban yang berlaku di Indonesia menggunakan sumber resmi terbaru untuk transaksi aktual."}],author:indonesianEditorialAuthor,reviewedBy:indonesianTechnicalReviewer,schemaData:{brand:"PowerBaseFit",manufacturer:"PowerBaseFit",category:"Panduan pengadaan B2B",specifications:[{name:"Topik",value:profile.keyword},{name:"Intent",value:profile.intent}],breadcrumbs:[{name:"Beranda",path:"/id"},{name:"Panduan",path:"/id/blog"},{name:profile.h1,path}],extra:{primaryKeyword:profile.keyword,searchIntent:profile.intent}},images,internalLinks:[{targetContentId:"products-hub",label:"Jelajahi semua produk"},{targetContentId:"factory",label:"Pelajari produksi dan kualitas"},{targetContentId:"oem-private-label",label:"Tinjau OEM dan merek sendiri"},{targetContentId:"contact",label:"Kirim permintaan B2B"}]});
}

function versionFor(entity:ContentEntity){if(core[entity.id])return coreVersion(entity,core[entity.id]);if(guides[entity.id])return guideVersion(entity,guides[entity.id]);if(entity.type==="product")return productVersion(entity);throw new Error(`Indonesian localization missing for ${entity.id} (${entity.type})`);}

export const indonesianExcludedContentIds=[...excludedIds];
export function withIndonesianLocalization(manifest:ContentManifest):ContentManifest{
  const entities=manifest.entities.map((entity)=>{
    const eligible=Boolean(entity.versions.en)||entity.id==="oem-private-label"||Boolean(guides[entity.id]);
    if(!eligible||excludedIds.has(entity.id))return entity;
    if(entity.versions.id)throw new Error(`Indonesian localization duplicates ${entity.id}`);
    return{...entity,versions:{...entity.versions,id:versionFor(entity)}};
  });
  return{...manifest,entities};
}
